with WithAncestors AS (SELECT itemid FROM AncestorIds2 WHERE AncestorId in (100) ),WithItemLinkItemIds AS (select ItemLinks2.LinkedId From ItemLinks2 join withancestors on withancestors.itemid=itemlinks2.itemid  where ItemLinks2.Type in (2,3))select A.Id,A.Name from mediaitems A join fts_search9 on A.Id=fts_search9.RowId and fts_search9 match @SearchTerm where A.Id in WithItemLinkItemIds ORDER BY Rank ASC LIMIT 12
